import{C as n,o as e,c as l,a5 as a,E as h}from"./chunks/framework.CW28V7p_.js";const k=JSON.parse('{"title":"2. Git","description":"","frontmatter":{},"headers":[],"relativePath":"module-0/2-git.md","filePath":"module-0/2-git.md","lastUpdated":1780937944000}'),p={name:"module-0/2-git.md"},c=Object.assign(p,{setup(o){const i={id:"m0-2-git",title:"🧠 Mini-check: Git",intro:"3 питання — фокус на тому що ти реально робиш у workflow.",questions:[{type:"diagnose",q:'Ти бачиш error: "Your local changes to the following files would be overwritten by checkout". Які з цих причин могли його спричинити (обери всі)?',options:["Ти раніше робила sed на файлі і не закоммітила","Хтось інший push нув зміни у віддалений repo","Файл у target branch/tag відрізняється від файлу що ти змінила","Working tree має staged changes що конфліктують з target"],correct:[0,2,3],explanation:"Помилка про ЛОКАЛЬНІ зміни — git не дозволить overwrite їх checkout-ом. Триггер: твоя локальна зміна + різний файл у target. Чужі push у remote не впливають поки ти не зробиш pull. Staged changes теж блокують якщо вони конфліктують."},{type:"command",q:"Як відкинути локальні зміни в одному файлі (наприклад config.toml)? Напиши команду.",accepts:["git checkout -- config.toml","git restore config.toml","git checkout config.toml"],ideal:"git checkout -- config.toml",explanation:"git checkout -- <file> класичний синтаксис, працює усюди. Сучасний еквівалент: git restore <file>. Без -- може бути ambiguous якщо branch має таке ж імя як файл (рідкісно але буває)."},{type:"compare",q:"У чому різниця між branch і tag у git? Перерахуй 2-3 ключові пункти.",ideal:`1. Branch рухається з новими commits (вказівник просувається), tag immutable (привязаний до конкретного commit назавжди).
2. Branch для активної розробки (новий код), tag для releases (snapshot готової версії).
3. Checkout на branch стає на її tip і можеш робити commits. Checkout на tag стає detached HEAD, commits будуть orphaned.
4. Branch можна швидко створити/видалити локально. Tag зазвичай створюють і пушать у remote як публічний marker.`,explanation:"Ключове — mutability (branch рухається, tag ні) і призначення (розробка vs release). Якщо ти описала ці два пункти — це 80%+ правильне розуміння. Detached HEAD як deeper concept — bonus."}]};return(r,s)=>{const t=n("Quiz");return e(),l("div",null,[s[0]||(s[0]=a("",70)),h(t,{data:i}),s[1]||(s[1]=a("",6))])}}});export{k as __pageData,c as default};
